const leads = $('Get All Leads').all().map(i => i.json);
const content = $('Get Content Queue').all().map(i => i.json);

const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();

const recentLeads = leads.filter(l => l.created_time > oneWeekAgo);
const recentContent = content.filter(c => c.created_time > oneWeekAgo);

const leadsAdded = recentLeads.length;
const dmsReady = recentLeads.filter(l => l.properties?.Status?.status?.name === 'DM Ready').length;
const dmsSent = recentLeads.filter(l => l.properties?.Status?.status?.name === 'DM Sent').length;
const replied = recentLeads.filter(l => l.properties?.Status?.status?.name === 'Replied').length;
const booked = recentLeads.filter(l => l.properties?.Status?.status?.name === 'Call Booked').length;
const scriptsGenerated = recentContent.length;
const topHook = recentContent[0]?.properties?.Hook?.title?.[0]?.text?.content || 'N/A';
const weekLabel = new Date().toISOString().slice(0, 10);

const prompt = `You are a business analyst reviewing weekly performance for a content automation system.

WEEK: ${weekLabel}

ACTIVITY:
- Scripts/hooks generated: ${scriptsGenerated}
- Leads researched: ${leadsAdded}
- DMs drafted: ${dmsReady}
- DMs sent: ${dmsSent}
- Replied: ${replied}
- Calls booked: ${booked}
- Top hook: "${topHook}"

Write a concise weekly performance report:
1. SUMMARY (3-5 sentences): What happened. What worked. What didn't. Treat reader like a founder with 2 minutes.
2. RECOMMENDATIONS (exactly 3 bullets): Highest-leverage actions for next week. Specific. Not generic.

Return as JSON only:
{
  "summary": "...",
  "recommendations": "• Action 1\n• Action 2\n• Action 3"
}`;

return [{ json: { prompt, weekLabel, scriptsGenerated, leadsAdded, dmsReady, dmsSent, replied, booked, topHook } }];

const raw = $('Run Claude').first().json.output || '';
const stats = $('Aggregate Stats').first().json;

let report = { summary: '', recommendations: '' };
try {
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start !== -1 && end !== -1) {
    report = JSON.parse(raw.slice(start, end + 1));
  }
} catch(e) {
  report.summary = raw.slice(0, 1000);
}

return [{ json: { ...stats, ...report } }];
